mapper.select:
SELECT MAX(MA.CAN_READ) AS can_read, MAX(MA.CAN_CREATE) AS can_create, MAX(MA.CAN_UPDATE) AS can_update, MAX(MA.CAN_DELETE) AS can_delete, MAX(MA.CAN_APPROVE) AS can_approve, MAX(MA.CAN_CANCEL) AS can_cancel, MAX(MA.CAN_DOWNLOAD) AS can_download, MAX(MA.CAN_MASK_VIEW) AS can_mask_view FROM SMS.TB_MENU M INNER JOIN SMS.TB_MENU_AUTH MA ON MA.MENU_ID = M.MENU_ID WHERE M.USE_YN = 'Y' AND MA.USE_YN = 'Y' AND M.MENU_URL = #{menuUrl} AND MA.ROLE_CD IN
#{roleCode}
GROUP BY M.MENU_ID
